const ALLOWED_COUNTRIES = new Set([
  'United States','Canada','United Kingdom','Ireland','Germany','France',
  'Netherlands','Belgium','Switzerland','Austria','Luxembourg','Denmark',
  'Sweden','Norway','Finland','Iceland','Spain','Portugal','Italy','Greece',
  'Malta','Cyprus','Poland','Czech Republic','Slovakia','Hungary','Romania',
  'Bulgaria','Croatia','Slovenia','Estonia','Latvia','Lithuania','Serbia',
  'Ukraine','Georgia','Armenia','Moldova'
]);

const raw = $input.first().json;
const items = Array.isArray(raw) ? raw : [];
const cutoffMs = Date.now() - (2 * 24 * 60 * 60 * 1000); // 2 days

const jobs = [];
for (const item of items) {
  if (item.type !== 'detail') continue;

  const data = item.data || {};
  const opening = data.opening || {};
  const clientData = data.client || {};
  const budgetData = data.budget || {};

  // Age filter
  const posted = opening.postedOn || opening.publishTime || '';
  if (posted && new Date(posted).getTime() < cutoffMs) continue;

  // Geo filter — skip known non-allowed countries
  const loc = clientData.location || {};
  const country = typeof loc === 'object' ? (loc.country || '') : '';
  if (country && !ALLOWED_COUNTRIES.has(country)) continue;

  // Budget
  let budget = 'Not specified';
  if (budgetData.fixedBudget) budget = `$${Number(budgetData.fixedBudget).toLocaleString()} fixed`;
  else if (budgetData.hourlyRate?.min) budget = `$${budgetData.hourlyRate.min}–$${budgetData.hourlyRate.max}/hr`;

  // Skills
  const skillsRaw = data.skills || opening.skills || [];
  const skills = skillsRaw.map(s => typeof s === 'object' ? s.name : s).filter(Boolean).slice(0, 6);

  // Clean URL
  let url = item.link || '';
  if (url.includes('?')) url = url.split('?')[0];

  const stats = clientData.stats || {};

  jobs.push({
    title: item.title || 'Untitled',
    description: (opening.description || '').slice(0, 1500),
    url,
    budget,
    skills,
    country: country || 'Unknown',
    client_spent: stats.totalSpent || 0,
    client_rating: stats.rating || 0
  });
}

if (jobs.length === 0) return [];
return jobs.map(j => ({ json: j }));

// Extract score from Claude response and merge with original job data
const claudeResp = $input.item.json;
const job = $('Parse + Filter Jobs').item.json;

const text = claudeResp.content?.[0]?.text || '{}';
let score = 0;
let reason = 'Could not score';
try {
  const match = text.match(/\{[\s\S]*?\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    score = parseInt(parsed.score) || 0;
    reason = parsed.reason || '';
  }
} catch(e) {}

return [{ json: { ...job, score, reason } }];

